// Minimal silent webm used by NoSleep.js to prevent display sleep on browsers
// without Wake Lock API support (Safari, older TVs, some Chromecast sources).
const NO_SLEEP_WEBM =
  "data:video/webm;base64,";

type KeepaliveHandle = {
  stop: () => void;
};

let activeHandle: KeepaliveHandle | null = null;
let activeConsumers = 0;

function createHiddenVideo() {
  const video = document.createElement("video");
  video.setAttribute("title", "Display keepalive");
  video.setAttribute("playsinline", "true");
  video.setAttribute("muted", "true");
  video.setAttribute("loop", "true");
  video.muted = true;
  video.playsInline = true;
  video.style.cssText =
    "position:fixed;left:-9999px;top:-9999px;width:1px;height:1px;opacity:0;pointer-events:none;";
  video.src = NO_SLEEP_WEBM;
  document.body.appendChild(video);
  return video;
}

function createCanvasTicker() {
  const canvas = document.createElement("canvas");
  canvas.width = 2;
  canvas.height = 2;
  canvas.style.cssText =
    "position:fixed;left:-9999px;top:-9999px;width:1px;height:1px;opacity:0;pointer-events:none;";
  document.body.appendChild(canvas);
  const ctx = canvas.getContext("2d");
  let rafId = 0;

  const tick = () => {
    if (ctx) {
      ctx.fillStyle = "#000";
      ctx.fillRect(0, 0, 2, 2);
    }
    rafId = requestAnimationFrame(tick);
  };
  rafId = requestAnimationFrame(tick);

  return () => {
    cancelAnimationFrame(rafId);
    canvas.remove();
  };
}

function startKeepaliveEngine() {
  const video = createHiddenVideo();
  const stopCanvas = createCanvasTicker();
  let videoRetryTimer: number | null = null;

  const playVideo = () => {
    void video.play().catch(() => {
      videoRetryTimer = window.setTimeout(playVideo, 2000);
    });
  };

  playVideo();

  const watchdogTimer = window.setInterval(() => {
    if (video.paused && !video.ended) {
      playVideo();
    }
  }, 30_000);

  const stop = () => {
    if (videoRetryTimer) window.clearTimeout(videoRetryTimer);
    window.clearInterval(watchdogTimer);
    video.pause();
    video.remove();
    stopCanvas();
    activeHandle = null;
  };

  activeHandle = { stop };
  return stop;
}

export function startDisplayKeepaliveFallback(): () => void {
  if (typeof window === "undefined") return () => {};

  activeConsumers += 1;
  if (!activeHandle) {
    startKeepaliveEngine();
  }

  return () => {
    activeConsumers = Math.max(0, activeConsumers - 1);
    if (activeConsumers === 0) {
      activeHandle?.stop();
    }
  };
}

export function stopDisplayKeepaliveFallback() {
  activeConsumers = 0;
  activeHandle?.stop();
}
